parameters.functionCode:
const body = items[0].json.body || items[0].json;
const source = body.source || 'kiosk';
const sessionId = body.session_id || body.sessionId || 'unknown';

// Extract CV fields from request
const cvData = {
  name: body.name || '',
  phone: body.phone || '',
  education: body.education || '',
  experience: body.experience || '',
  skills: body.skills || '',
  voice_text: body.voice_text || '',
  lang: body.lang || 'en',
  source: source,
  session_id: sessionId,
  timestamp: new Date().toISOString()
};

// If voice text provided but no structured fields, parse voice input
if (cvData.voice_text && !cvData.name) {
  cvData.needs_parsing = true;
}

return [{ json: cvData }];

values.content:
You are a professional CV writer for Aego Cyber Cafe in Nyatike, Migori County, Kenya. Create a clean, professional CV in plain text format suitable for printing on A4 paper.

Customer Details:
- Name: {{$json.name}}
- Phone: {{$json.phone}}
- Education: {{$json.education}}
- Experience: {{$json.experience}}
- Skills: {{$json.skills}}

Requirements:
1. Use clear section headings
2. Keep it to 1 page
3. Use simple formatting (no special characters that might not print)
4. Include a professional objective statement
5. Format for Kenyan job market
6. Language: {{$json.lang === 'sw' ? 'Swahili' : $json.lang === 'lu' ? 'Dholuo' : 'English'}}

Return the CV as plain text.

parameters.functionCode:
const cvContent = items[0].json.choices?.[0]?.message?.content || items[0].json.text || '';
const requestData = $('Parse CV Data').first().json;

return [{
  json: {
    cv_content: cvContent,
    customer_name: requestData.name,
    phone: requestData.phone,
    service_type: 'cv',
    amount: 100,
    status: 'pending_approval',
    session_id: requestData.session_id,
    source: requestData.source,
    created_at: new Date().toISOString()
  }
}];

const dbResult = items[0].json;
const cvData = $('Prepare CV Result').first().json;

return [{
  json: {
    ...cvData,
    id: dbResult.id || dbResult.lastID,
    action: 'staff_approval_required',
    message: `New CV request from ${cvData.customer_name} - needs approval`,
    notification_type: 'staff'
  }
}];
